INSERT INTO books (id, title_ar, title_en, summary_ar, summary_en, cover_url, content_pages, is_free_to_read, genre, sub_genre, author, publisher, publication_year, page_count, language, age_rating, created_at) VALUES
  ('f1fd47ce-1f0d-43d4-99cf-1113d521664b', 'ألف ليلة وليلة', 'One Thousand and One Nights', 'مجموعة من الحكايات الشعبية المتشعبة والروايات التي جُمعت على مرّ القرون، وتضمّ الحكايات المتداخلة التي تحكيها شهرزاد لزوجها الملك شهريار، تبدأ كلّ ليلة بحكاية جديدة وتتركها معلّقة لتمنع الملك من إعدامها.', 'A timeless collection of folk tales compiled over centuries. The frame story involves Scheherazade telling stories to King Shahryar night after night, suspending each story at a cliff-hanger to survive until the next evening.', 'https://www.neelwafurat.com/images/lb/abookstore/covers/carton/33/33754.jpg', ARRAY['قالت شهرزاد لأختها دنيازاد: اعلمي يا أختي أن الحكاية أقوى من السيف. دخلت على الملك شهريار في ذلك الليل الأول وكان قلبها يدقّ بقوةٍ لكن وجهها كان هادئاً كسطح البحر في الفجر. قالت: يا ملك الزمان، هل تأذن لي أن أحكي لك حكاية؟ وكان الملك قد نسي طعم السعادة منذ أمدٍ بعيد، بنى حوله سوراً من الغضب والشك. لكن حين بدأت شهرزاد تحكي وجد نفسه يُصغي كطفلٍ يسمع أول قصة في حياته.', 'كان من سحر شهرزاد أنها تعرف متى تتوقف. عند اقتراب الفجر كانت تقطع حكايتها عند أشد لحظاتها إثارةً وتقول: وكان الصباح قد أدرك شهرزاد فسكتت عن الكلام المباح. فيقول الملك في نفسه: لن أقتلها الليلة، دعها تكمل الحكاية. وهكذا كانت الحكاية سلاحها ودرعها. شيئاً فشيئاً بدأ قلب الملك القاسي يلين، فالحكايات كانت تذكّره أن في الدنيا خيراً وشراً وأن الإنسان ليس شريراً بطبعه بل بما صنعه الألم منه.', 'في تلك الليالي الطويلة مرّت أمام الملك عوالم لم يرها قط: بغداد هارون الرشيد بأسواقها وقصورها، والسندباد البحري يواجه الموج والوحوش، وعلي بابا أمام الكهف السحري. كانت الكلمات وحدها قادرةً على فعل ما عجزت عنه السيوف، تكسر القيود وتبني الجسور وتغسل القلوب من صدئها. كانت شهرزاد تعرف ما لا يعرفه الملوك: أن الإنسان يمكن أن ينجو بقصةٍ واحدة تُقال في الوقت المناسب.', 'ركب السندباد بحره الأول وهو لا يعرف ما ينتظره، وكانت الأمواج تتكلم لغةً لا يفهمها أحدٌ إلا من عاشها. نزل مع رفاقه على جزيرةٍ بدت مستويةً فأشعلوا النار، ثم اهتزت الجزيرة وانطلقت في الماء، وكانوا على ظهر سمكةٍ عملاقة تنام في قاع البحر. وفي كل رحلةٍ جديدة كان السندباد يعود بدرسٍ مختلف: أن الأرض أكبر مما نتخيل وأن الإنسان أصغر مما يظن وأشجع مما يعرف.', 'مرّت ألفٌ وليلة وفي الليلة الأخيرة قالت شهرزاد: يا ملك الزمان، هذه آخر حكاياتي وقد وضعت أمامك كنز الكلمات كله. فنظر إليها الملك طويلاً وقال: لن تموتي يا شهرزاد، فلو قتلتك لما بقي في الدنيا من يعرف أن يُخبر الإنسان ما يحتاج لسماعه. وهكذا ظلّت ألف ليلة وليلة حيّةً على مرّ القرون، شاهدةً على أن الحكاية هي أقوى سلاحٍ صنعه البشر في مواجهة الخوف والموت والنسيان.'], TRUE, NULL, NULL, NULL, NULL, NULL, NULL, 'العربية', NULL, '2026-06-15 15:03:10.998459+00'),
  ('49038c92-48b3-41a6-9b8b-e269736fd457', 'رجال في الشمس', 'Men in the Sun', 'رواية قصيرة للأديب الفلسطيني غسان كنفاني، تحكي قصة ثلاثة لاجئين فلسطينيين يحاولون الوصول إلى الكويت بحثاً عن عمل وحياة أفضل، مخبّئين في صهريج شاحنة. الرواية استعارة قوية عن المعاناة الفلسطينية والصمت المميت.', 'A novella by Palestinian writer Ghassan Kanafani. Three Palestinian refugees attempt to reach Kuwait for work, hidden in a water tanker. A powerful allegory of Palestinian suffering, displacement, and the deadly silence of a people.', 'https://www.daralfiker.com/sites/default/files/styles/page/public/whatsapp_image_2025-12-03_at_10.01.04_am.jpeg?itok=-r59kPMp', ARRAY['الصحراء لم تكن تعرف الرحمة. كان الحر يقع على الأرض كحجرٍ ثقيل وكانت الشمس تلتهم كل شيءٍ في طريقها. جلس أبو قيس في ظل صخرةٍ صغيرة ومسح وجهه بكفّه ونظر إلى الطريق الممتد أمامه. كان الطريق يؤدي إلى الكويت حيث العمل والمال والحياة التي غاب عنها منذ فرّ من فلسطين وأرضه.', 'تذكّر أبو قيس ليلةً بعيدة حين كان نائماً في أرضه وكانت رائحة التراب المبلل بالمطر تملأ أنفه. كانت الزيتونات تهمس في الريح وكانت امرأته نائمةً بجانبه. فقدها وفقد الأرض في عامٍ واحد. كل ما يفعله الآن هو لأجل ما تبقّى: أبناؤه في المخيم الذين ينتظرون خبزاً وأملاً وأباً يعود.', 'أبو الخيزران كان يقود شاحنته كأنها مملكته الوحيدة. رجلٌ فقد شيئاً لا يُعوّض في حربٍ لا يريد أن يتذكرها. قال للرجال الثلاثة: سأنقلكم في الخزان الفارغ. وكانت الخطة بسيطةً كما يبدو الخطر دائماً قبل أن يتجلّى. مروان وأسعد وأبو قيس نظر كلٌّ منهم إلى الآخر وكانت في أعينهم إجابةٌ واحدة: لا خيار آخر.', 'دخل الرجال الخزان وأُغلق الباب عليهم. كانت الحرارة في الداخل لا تُطاق وكان الصمت مرعباً. كل واحدٍ منهم كان يفكر بشيءٍ مختلف: أبو قيس بأرضه ومروان بمستقبله وأسعد بحياةٍ لم تبدأ بعد. كانت الدقائق تمرّ كأنها ساعات والهواء يصبح أكثر ثقلاً مع كل نفَس.', 'توقفت الشاحنة طويلاً عند نقطة التفتيش وكان أبو الخيزران منشغلاً. حين فتح الخزان أخيراً كان الصمت من الداخل من نوعٍ آخر. دقّ على جدار الخزان مرةً ومرتين ثم نادى ولم يُجب أحد. الشمس أخذت الرجال الثلاثة في غفلةٍ من الزمن ومن العالم الذي لم يكترث لمصيرهم. غسان كنفاني يسألنا: لماذا لم يدقّوا على الجدران؟'], TRUE, NULL, 'سياسي / إنساني', 'غسان كنفاني', 'مؤسسة الأبحاث العربية', 1963, 108, 'العربية', 'مناسب للجميع', '2026-06-15 15:03:10.998459+00'),
  ('4b4aaa41-b4d3-41cf-8589-692d97d5ae3a', 'عمارة يعقوبيان', 'The Yacoubian Building', 'رواية للكاتب المصري علاء الأسواني تتخذ من عمارة يعقوبيان في وسط القاهرة مسرحاً لها. تتداخل فيها قصص سكانها من مختلف الطبقات والأجيال، لتكشف عن مفارقات المجتمع المصري وتناقضاته.', 'A novel by Egyptian writer Alaa Al Aswany set in a famous Cairo building. Stories of residents from different classes and generations intertwine to reveal the contradictions of Egyptian society.', 'https://www.neelwafurat.com/images/lb/abookstore/covers/normal/324/324381.jpg', ARRAY['في الأربعينيات من القرن الماضي، حين شُيّدت عمارة يعقوبيان في قلب القاهرة بطرازها الأوروبي الأنيق الرفيع، كانت ملجأ الباشوات والأعيان وكبار التجار اليونانيين والأرمن والإيطاليين الذين آثروا القاهرة على عواصم العالم الكبرى. كانت شققها الفسيحة تموج بالحياة الراقية: حفلات الموسيقى الكلاسيكية والمآدب الصاخبة والعناق الدافئ بين الثقافات المتعددة في مدينة كانت تعرف كيف تحتضن العالم بكل تنوّعاته وتناقضاته. أما اليوم، فقد تحوّلت العمارة إلى عالم متعدد الطبقات لا تلتقي طبقاته إلا نادراً: في الشقق الفسيحة المطلّة على الشارع يتمسّك بقايا أرستقراطيين بذكريات الزمن الجميل كمن يمسك بحبال الهواء، وعلى السطح تتراصّ غرف الصفيح والخشب المتهالك كأبراج فقر فوق قلعة عجز. والعمارة بكل طوابقها وأسرارها المتراكمة ليست إلا مصر المصغّرة التي يصعب فهمها وأشدّ صعوبةً تغييرها.', 'كان زكي بك الدسوقي يجلس في مكتبه الواسع المطلّ على شارع طلعت حرب، يُقلّب في أوراق لا يقرؤها وعيناه تتجوّلان في فراغ الذاكرة البعيدة. كان الأخير من سلالة أرستقراطية عريقة درست في باريس وتشرّبت ثقافة الغرب ثم عادت لتُحبّ مصر بعيون مختلفة ترى فيها ما لا يراه المصريون أنفسهم. لكن مصر الجديدة لم تتسع له كما اتّسعت لأمثاله من أبناء جيله. كان يتذكر الصالونات الأدبية والمسارح الراقية والمقاهي الإيطالية التي كانت القاهرة تزخر بها في زمن غابر، ويتذكر وجوه أصدقائه الذين فرّقتهم الهجرة والمنافي وتقلّبات التاريخ. كان الحنين يجثم على صدره كأنه صخرة رسخت ولا تتزحزح، وكانت شقّته المليئة بالكتب والصور القديمة والتحف النادرة تبدو له أحياناً كمتحف يعيش فيه وحيداً محتجزاً بين جدران زمن لن يعود.', 'صعد طه الشاذلي الدرج الرخامي البارد بخطوات ثقيلة تُعبّر عمّا تعجز عنه الكلمات، وفي يده ورقة الرفض التي تحمل ختماً رسمياً بارداً لا يهتم بكسر القلوب أو تحطيم الأحلام. كان ابن حارس البواية يحمل في صدره أملاً ضخماً دفعه إلى التقدّم لكلية الشرطة، إذ كان يؤمن إيماناً راسخاً أن الجدارة وحدها كافية لفتح الأبواب الموصدة أمام أبناء الفقراء. لكن الأبواب لها مفاتيح سرّية لم يعلّمه إياها أبوه العامل البسيط المخلص. رفضوه بسبب العنوان الذي يحمله: لأن أباه يسكن في بواية عمارة لا في شقة على درج. شعر بإهانة حوّلت فيها حلمه إلى باب موصد وإلى حاجز طبقي صلب لا تكسره الكفاءة ولا الإرادة ولا سنوات الدراسة المضنية. وفي تلك اللحظة بالذات، أُغلق باب ووُلدت فكرة في الظلام، وبدأت رحلة لم يكن طه الشاذلي يتخيّل أنها ستأخذه إلى ما أخذته إليه.'], FALSE, NULL, 'واقعي / اجتماعي', 'علاء الأسواني', 'مكتبة مدبولي', 2002, 280, 'العربية', '+18', '2026-06-15 15:03:10.998459+00'),
  ('d7213952-ecd0-4b00-92da-94c3575b4cf2', 'زقاق المدق', 'Midaq Alley', 'رواية للأديب المصري الحاصل على جائزة نوبل نجيب محفوظ. تصوّر حياة سكان زقاق المدق في القاهرة القديمة، وتكشف عن طموحاتهم وأحلامهم ومآسيهم في حقبة الحرب العالمية الثانية.', 'A novel by Nobel Prize winner Naguib Mahfouz set in a Cairo alley during WWII. It vividly portrays the lives, dreams, ambitions and tragedies of the alley inhabitants.', 'https://www.alquds.co.uk/wp-content/uploads/2024/08/04-33-730x438.jpg', ARRAY['زقاق المدق حيٌّ قديم يقع في قلب القاهرة الشعبية، يمتد بين بيوت عتيقة تتكئ على بعضها كأعمدة في شيخوخة مجيدة. لا يتجاوز طوله بضعة أمتار، ولا يختلف ظاهره عن عشرات الأحياء المتشابهة في الحارة المصرية القديمة، غير أنه يحمل في داخله عالماً كاملاً بكل ما تعنيه الكلمة من معنى ثريّ عميق. كانت الحياة فيه تبدأ قبل شروق الشمس بصوت باعة الفطائر ومنادي القهوة الصباحية، وتنتهي بعد منتصف الليل بأصوات الحجج والمشاجرات العابرة التي لا تخلو منها ليلة واحدة. كانت البيوت المتراصّة على جانبيه تشهد مواليد وأفراحاً وأتراحاً في اليوم الواحد، وكانت حكاياتها تتشابك وتتداخل حتى لا يعرف أحد أين تنتهي قصة وأين تبدأ أخرى. وكانت الشمس لا تصل إلى أرض الزقاق إلا في ساعات قليلة من كل يوم، فكان يبدو دائماً في نور معتم يزيده غموضاً وجاذبيةً لا تُفسَّر ولا تُقاوم. وكان نجيب محفوظ يعرف هذا الزقاق معرفة من نشأ في أزقّة القاهرة وشرب من مائها وتشرّب روحها.', 'كانت حميدة تقف كل صباح عند نافذتها المطلّة على الزقاق، تنظر إلى المارة بعيون تتوقّد بنار طموح لا تُطفئه الحياة الضيّقة ولا تُخمده الأيام المتكرّرة. كانت فتاةً جميلة بجمال لافت لا يُناسب محيطها البسيط، كأن القدر أخطأ عنوانها حين وضعها هنا في هذا الزقاق بين جدران لا تتسع لأحلامها الكبيرة. كانت تحلم بحياة أخرى تلمحها كلما مشت في شوارع القاهرة الكبرى، حياة تنبض بالضوء والثياب الأنيقة والنظرات المعجبة من عيون لا تعرفها. أما حياتها الحقيقية فكانت تدور في دوامة ضيّقة بين البيت ومصنع النسيج القريب وسهرات الزقاق المكتظّة بالوجوه ذاتها. كانت أمها تعرف ما يدور في رأسها وتخشاه خشية المرأة الخبيرة بأثمان الأحلام الكبيرة في البيئات الصغيرة. غير أن حميدة كانت تُصمّ أذنيها عن كل تحذير، إذ كانت تؤمن في أعماقها أن حياتها الحقيقية لم تبدأ بعد، وأنها في انتظار ما لا تعرف اسمه لكنها تشعر بقدومه.', 'في مقهى كرشة الذي يجلس عند مدخل الزقاق جلسة المُرابط، كان الرجال يجتمعون في كل مساء لتبادل الأحاديث وهضم الهموم وتمرير الوقت الثقيل بكل ما يحمله من أعباء. كان الشيخ درويش يجلس في الزاوية الخلفية كعادته الراسخة، يتمتم بآيات قرآنية ويُصغي إلى ما لا يسمعه الآخرون في ضجيجهم. كان الناس يقولون إنه فقد عقله يوم خسر عمله وزوجته في يوم واحد، غير أن للمجانين حكمةً لا تُتاح لأصحاب العقول السليمة المثقلة بأوهامها وقيودها. كان يرى في الناس ما لا يرون في أنفسهم، ويقول كلاماً غامضاً تفهمه الأيام بعد فوات الأوان. وفي المقهى ذاته، كان عباس الحلو يحلم بأن يُجمع مالاً كافياً يتقدّم به لخطبة حميدة الجميلة. كان بسيطاً نظيف القلب لا يُحسن الكلام الجميل المصقول، لكن قلبه كان يُحبّ بصدق وعمق لا تقوى عليه الكلمات المزخرفة. غير أن القدر كان يُعدّ لحميدة مصيراً آخر لم يخطر على بال عباس ولا على بال أحد في الزقاق.'], FALSE, NULL, 'واقعي / دراما', 'نجيب محفوظ', 'مكتبة مصر', 1947, 300, 'العربية', 'مناسب للجميع', '2026-06-15 15:03:10.998459+00'),
  ('0d212b5a-79e7-4a3d-a5a8-1dc80597d084', 'أولاد حارتنا', 'Children of the Alley', 'ملحمة روائية كبرى لنجيب محفوظ تحكي تاريخ البشرية من خلال رموز. تتناول علاقة الإنسان بالإله والسلطة والعدالة، ممثلةً في شخصيات الأبطال المتعاقبين على حارة واحدة تمثّل الكون كله.', 'An epic allegory by Naguib Mahfouz recounting human history through symbols. It explores humanity''s relationship with God, authority, and justice through characters in a symbolic alley.', 'https://assets.asfar.io/uploads/2021/02/%D8%A7%D9%94%D9%88%D9%84%D8%A7%D8%AF-%D8%AD%D8%A7%D8%B1%D8%AA%D9%86%D8%A7-%D9%86%D8%AC%D9%8A%D8%A8-%D9%85%D8%AD%D9%81%D9%88%D8%B8.jpg', ARRAY['كان الجبلاوي يعيش في البيت الكبير الذي يهيمن على الحارة كلها هيمنةً مريبة لا تشبه هيمنة البشر. بيتٌ ضخم تحيط به أسوار عالية كأسوار القلاع، تفصله عن الحارة فصلاً تاماً كأنه في عالم آخر لا يخضع لقوانين الحارة ولا لسلطة الفتوّات. لم يكن أحدٌ يراه بعينيه في العصور الأخيرة، لكن الجميع كانوا يُحسّون بوجوده إحساساً راسخاً لا يقبل الشكّ أو التساؤل. كانت اسمه يُتداول في الحارة بنبرة فيها من الخشية والتعظيم مثلما فيها من الأمل والمحبة العميقة. وكانت قصصه تُروى على مرّ الأجيال حتى صارت في أذهان الناس أقرب إلى الأساطير منها إلى حوادث التاريخ. وكانت الحارة تحيا في ظلّه وتستمدّ هويّتها من ذكراه حتى حين يتصارع أبناؤها على الوقف الذي تركه ميراثاً مشتركاً للجميع. كانت الحارة كلّها سؤالاً كبيراً لم يجرؤ أحدٌ على طرحه بصوت عالٍ، وكانت حياة أهلها مرآةً تعكس صراع الإنسان الأزلي مع عجزه وتطلّعه إلى ما هو أعلى منه.', 'قال إدريس وهو يُمسك بالحجر بيد مرتجفة من عاصفة الغضب التي تجتاحه من الداخل: لماذا يحظى الآخرون بما لا أنال؟ ألست ابن الجبلاوي أيضاً؟ ألا يسري في عروقي الدم ذاته الذي يجري في عروق من اصطفاهم دوني؟ كان في صوته مزيج مُعقّد من الحسرة والمرارة والتساؤل الأزلي الذي لا يجد له الإنسان جواباً مُقنعاً في أي زمان أو مكان. نظر إلى البيت الكبير من وراء الأسوار الشاهقة نظرة المحروم المطرود الذي لا يعرف ذنبه، ثم رمى الحجر بعيداً وانطلق يشقّ طريقه في الحارة المظلمة المكتظّة بالأصوات والروائح والأعمار المتشابكة. كانت الحارة تتفرّج عليه في صمت المعتاد على مشاهد الحزن والطرد والهزيمة المتكرّرة. تلك اللحظة من الرفض كانت بذرة كل ما سيأتي بعدها من صراعات وآلام وانتفاضات، كما أن البذرة الصغيرة تحمل في طيّاتها شجرةً بكاملها بجذورها وفروعها وكل ثمارها المرّة والحلوة.', 'جاء جبل إلى الحارة يوماً حاملاً في قلبه رسالة التحرّر وفي صوته شيء أشبه بصوت الحقّ. كانت الناس تتوقّف في طريقها لتنظر إليه بعيون تتأرجح بين الأمل الجارف والخوف العميق، بين الرغبة الصادقة في التصديق والخشية من خيبة أمل جديدة تُضاف إلى ركام الخيبات المتراكمة على مرّ السنين. كان يتكلّم بوضوح لا يحتمل اللبس، يقول إن وقف الجبلاوي للجميع وليس حكراً على حفنة من المتسلّطين، وإن الكرامة حقٌّ طبيعي لا مِنحةً تُمنح وتُسلب بحسب مزاج الأقوياء. كانت كلماته تتسرّب إلى القلوب المتعبة تسرّب الماء في الأرض الظمأى الجفيفة. غير أن الفتوّات وأصحاب النفوذ الذين اعتادوا السيطرة جيلاً بعد جيل لم يكونوا ليتركوا صوتاً يعلو دون أن يتصدّوا له بكل ما يملكون. كانت الحارة على موعد مع تحوّل كبير، والدماء التي ستُسفك ستكون الثمن الباهظ لسؤال بسيط: هل يستحقّ الإنسان حياةً بكرامة؟'], FALSE, NULL, NULL, NULL, NULL, NULL, NULL, 'العربية', NULL, '2026-06-15 15:03:10.998459+00'),
  ('1344d6fa-ce46-4903-ae21-8af873c6a498', 'مملكة الضباب', 'Kingdom of Fog', 'رواية مصرية تاريخية تحكي قصة امرأة في صعيد مصر تواجه العنف والتقاليد القاسية في بيئة اجتماعية مغلقة. ترصد واقع المرأة الريفية وصراعها المرير من أجل الكرامة والحرية في مجتمع يقيّد طموحاتها.', 'An Egyptian historical novel about a woman in Upper Egypt facing violence and harsh traditions in a closed social environment. It documents the reality of rural women and their bitter struggle for dignity and freedom in a society that constrains their ambitions.', 'https://encrypted-tbn0.gstatic.com/images?q=tbn:ANd9GcT1hvYBVjvYdmxw3Wc-EApYoQUV6tK6BoQwlXdWqGDfyQ&s=10', ARRAY['في أوائل القرن التاسع عشر كانت مصر تتنفس هواءً مغايراً. دخلت الأفكار الجديدة من بواباتٍ لم تكن موجودةً من قبل. في القاهرة تلك الأيام كانت نساءٌ يحملن أسئلةً لا يجرؤ الرجال على طرحها. زينب لم تكن تشبه بنات جيلها، كانت تقرأ في وقتٍ لم يكن فيه للنساء أن يقرأن وتتساءل في وقتٍ لم يكن للتساؤل مكان.', 'أمها كانت تقول لها: الفتاة السعيدة هي التي لا تسأل كثيراً. وكانت زينب تبتسم وتصمت وفي الداخل تشتعل الأسئلة. جاء محمد من الريف بعينين دهشتين، لم يكن يعرف المدينة ولم تعرفه. عمل في ورشةٍ قريبةً من حي الحسين وتعلّم الحرفة بأصابعه الماهرة وتعلّم خارج الورشة أن الفقر والغنى ليسا أقداراً سماويةً بل اختياراتٌ بشرية.', 'التقيا في ظروفٍ لم تكن لتحدث في زمنٍ عادي. كانت مصر تتقلّب بين القديم والجديد وكان الجميع يبحث عن موطئ قدم. وجد محمد في زينب صوتاً يقول ما يفكر فيه، ووجدت زينب في محمد شجاعةً تدعمها في مواجهة عالمٍ لا يريد أن يتغير. كانت القاهرة في تلك الأيام مسرحاً لصراعٍ بين زمنين.', 'لم تكن قصتهما قصة حبٍّ عادية. هي قصة جيلٍ كامل أراد أن يحيا بكرامةٍ في زمنٍ لم تكن الكرامة متاحةً للجميع. كانت ريم بسيوني تُجسّد في شخصيتيها تناقضات المجتمع المصري في لحظةٍ تحوّلٍ حقيقي، حين كانت كل خطوةٍ إلى الأمام تُكلّف ثمناً.', 'بقي منهما ما يبقى من كل الذين جاهدوا وصارعوا: أثرٌ في من يأتي بعدهم وذاكرةٌ تبقى حين تذهب الأجساد. سماريت رواية عن أناسٍ حقيقيين عاشوا في مصر وأرادوا أن يكونوا أحراراً في أرضهم وزمانهم. وكل من يقرأها اليوم يرى فيها شيئاً من نفسه في مواجهة عالمٍ يُقاوم التغيير.'], TRUE, 'رواية', 'تاريخي / اجتماعي', 'ريم بسيوني', 'دار الشروق', 2012, 320, 'العربية', '+16', '2026-06-19 21:06:16.269307+00'),
  ('9fea6e41-c13a-4bf1-aa35-79b4d5866a1e', 'ثلاثية غرناطة', 'Granada Trilogy', 'رواية تحكي قصة الأسرة الغرناطية بعد سقوط الأندلس، تجمع بين الحنين والألم والصراع على الهوية. تتتبع حياة الأبطال عبر ثلاثة أجزاء تمتد من سقوط غرناطة حتى القرن الحادي عشر الميلادي.', 'A novel about a Granadan family after the fall of Andalusia, blending nostalgia, pain, and the struggle for identity. It follows its heroes across three volumes spanning from the fall of Granada to the eleventh century.', 'https://assets.asfar.io/uploads/2020/07/%D8%AB%D9%84%D8%A7%D8%AB%D9%8A%D9%87-%D8%BA%D8%B1%D9%86%D8%A7%D8%B7%D9%87-300x441.jpg', ARRAY['كانت غرناطة في أواخر القرن الخامس عشر الميلادي تحتضر بهدوء. أسوارها العتيقة بدأت تتصدع لا من ضربات المدافع بل من ثقل الأيام. كان أبو جعفر سالم يمشي في أزقة المدينة القديمة كل صباح ويضع يده على الجدران كأنه يطمئنّ عليها. كانت الجدران باردةً تحت يده حتى في الصيف، وكأنها تحمل في حجارتها كل قرونٍ من الأمل والخسارة.', 'في يناير عام 1492 سقطت غرناطة. دخل فرديناند وإيزابيلا المدينة وكانت بوبو صغيرة السن تقف على سطح منزلها ترى الموكب الملكي من بعيد. لم تبكِ حينها، كانت صغيرةً على الفهم، لكنها تذكّرت طول عمرها تلك اللحظة التي أدركت فيها أن شيئاً ما مات إلى الأبد. الشمس كانت مشرقةً في ذلك اليوم وهذا ما جعله أكثر قسوةً.', 'أصدر الملكان أمراً بتنصير المسلمين أو ترحيلهم. وجد أبو جعفر نفسه أمام خيارٍ لا خيار فيه: أن يتخلى عن دينه أو يتخلى عن أرضه. أخذ وقتاً طويلاً ينظر في وجوه أبنائه ثم قرر: نبقى. ولم يكن يعرف حينها أن البقاء ثمنه أن تُغيّر اسمك ولغتك وملابسك وأن تُخفي صلاتك خلف أبوابٍ موصدة في الليل.', 'الذاكرة كانت سلاح آل سالم. كانت بوبو تحكي لأبنائها عن غرناطة الماضية، عن أسواقها وكتّابها ومساجدها وحماماتها. كانت ترى في أعينهم نوراً حين تصف لهم قصر الحمراء وهو لا يزال ملكاً لأهله. الذاكرة لم تكن ترفاً عندهم بل كانت هويةً وأماناً ورسالةً للأجيال القادمة لكي تعرف من أين أتت.', 'مرّت عقودٌ وتفرّق آل سالم. بعضهم بقي في غرناطة تحت اسمٍ مسيحي وبعضهم رحل إلى المغرب. لكن في كل مكانٍ حلّوا فيه كانوا يحملون في دمائهم رائحة الهال والعود التي علقت بذاكرتهم من أسواق غرناطة. تُخبرنا رضوى عاشور أن الأرض تُفقد لكن لا يُفقد من أحبّها، وأن الإنسان الذي يحفظ ذاكرته يحفظ نفسه.'], TRUE, 'رواية', 'تاريخي', 'رضوى عاشور', 'دار الهلال', 1994, 860, 'العربية', 'مناسب للجميع', '2026-06-19 21:06:16.269307+00'),
  ('d8ec41d6-2c83-4bab-9529-c92c313a1d6b', 'زقاق المدق', 'Midaq Alley', 'رواية تصور حياة ساكني زقاق المدق في حي شعبي قاهري عتيق خلال أحداث الحرب العالمية الثانية المضطربة. يرسم محفوظ بدقة متناهية صورة للتحولات الاجتماعية والحلم والإحباط في وجوه أبطاله البسطاء.', 'A novel portraying life in Midaq Alley, an old popular Cairene quarter, during the tumultuous events of World War II. Mahfouz paints with meticulous precision a portrait of social transformations, dreams, and frustrations on the faces of his humble heroes.', 'https://encrypted-tbn0.gstatic.com/images?q=tbn:ANd9GcQVTfe5tDknSBGPinb9y8UGsLrQlKB6isDKd8SOglRuHQ&s=10', ARRAY['كان زقاق المدق حياةً قائمةً بذاتها. له صوته الخاص الذي لا يشبه أي صوتٍ في القاهرة: مزيجٌ من أصوات حرفيين وبائعين ونساءٍ يتحدثن من نوافذٍ متقابلة. كان الزقاق يبدأ يومه قبل الفجر حين يُشعل الخباز فرنه وينتهي بعد منتصف الليل. وكان كل حجرٍ في جدرانه يحمل ذاكرةً لا يعرفها إلا من عاش فيه.', 'حميدة كانت أجمل بنات الزقاق وأعرفهن بذلك. كانت تقف كل مساءٍ عند بوابة الزقاق وتنظر إلى الشارع الكبير كأنها تنتظر شيئاً لا تعرف اسمه. أرادت ما هو أكبر من الزقاق: فستاناً مضيئاً وحذاءً أنيقاً وحياةً لا تشمّ فيها رائحة الخبز العتيق. وكان طموحها في ذاك الزقاق الضيق أكبر من الزقاق نفسه.', 'عباس الحلو كان يحبّها بصدقٍ بسيط. ذهب للعمل في معسكرات الإنجليز طمعاً في المال ليعود ويتزوجها. لم يكن يعرف أن المدن لا تنتظر أحداً وأن الناس يتغيرون حتى حين لا يريدون. كانت خطواته نحو المستقبل تقوده بعيداً عن الحاضر الذي يظن أنه سيعود إليه كما تركه تماماً.', 'سيد سنكر الرجل الغامض رأى في حميدة ما لم يره عباس: طمعاً مثل طمعه وقسوةً تحت طبقة الجمال. وعرض عليها ما لم يستطع عباس أن يعرضه. وكانت حميدة أمام خيارٍ تعرف في قرارة نفسها أنه ليس خياراً حقيقياً بل هروبٌ نحو وهمٍ أكبر من الوهم الذي تهرب منه.', 'آل أمر الزقاق كما تؤول الأمور دائماً. بعض الناس يبقون وبعضهم يرحلون. الزقاق نفسه بقي كما هو، أحجاره المتشققة ورائحة الليل فيه لا تتغير. نجيب محفوظ يُخبرنا أن أعظم مآسي الإنسان ليست في الكوارث الكبيرة بل في اللحظات الصغيرة التي يختار فيها غير الصواب وهو يعرف ذلك تماماً.'], TRUE, 'رواية', 'واقعي / دراما', 'نجيب محفوظ', 'مكتبة مصر', 1947, 300, 'العربية', 'مناسب للجميع', '2026-06-19 21:06:16.269307+00'),
  ('836dc886-8ad4-43e2-9d47-c063b011aa08', 'يا مريم', 'Ya Maryam', 'تحكي قصة سامي المسيحي العراقي الذي رفض مغادرة بغداد رغم موجات العنف الطائفي المتصاعد وتشبث بوطنه الجريح. رواية مؤثرة ترصد معاناة الأقليات والتحلل الاجتماعي في العراق المعاصر.', 'The story of Sami, an Iraqi Christian who refused to leave Baghdad despite rising sectarian violence, clinging to his wounded homeland. A moving novel that documents the suffering of minorities and social disintegration in contemporary Iraq.', 'https://m.media-amazon.com/images/S/compressed.photo.goodreads.com/books/1356583613i/15718933.jpg', ARRAY['بغداد التي أعرفها لم تعد موجودة. لا أعرف إن كانت موجودةً أصلاً خارج ذاكرتي. أم دانيال تجلس عند نافذتها وتنظر إلى الشارع الذي تغيّر كل شيءٍ فيه. الجيران الذين عرفتهم رحلوا الواحد تلو الآخر كالأضواء تُطفأ في بيتٍ كبير وتبقى الظلمة تملأ الفراغ الذي تركوه.', 'كانوا مسيحيين في العراق منذ قبل الإسلام ومنذ قبل الفتح العربي. جذورٌ ممتدةٌ في هذه الأرض أعمق من كثيرٍ من الجذور الأخرى. كانت الكنيسة القديمة في الحيّ تُطلّ على مسجدٍ قديم وكانا يُشاركان نفس الأذان ونفس الجرس في التقويم السنوي. كان الجيران يُهنّئ بعضهم بعضاً في الأعياد.', 'حين بدأ الخراب لم يبدأ بصوتٍ عالٍ. بدأ بهمساتٍ وخدشات صغيرة. رجلٌ يتلقّى رسالةً تهديدية. بيتٌ يُرسم عليه علامة. طفلٌ لا يعود من المدرسة. كانت أم دانيال تجمع هذه التفاصيل في قلبها وتفهم أن ما كان يبدو ثابتاً أبدياً كان في الحقيقة هشاً كالزجاج أمام الكراهية.', 'مريم هي العذراء التي تُصلّي لها أم دانيال كل يوم. وهي أيضاً اسمٌ يجمع الثقافتين: مريم في القرآن وفي الإنجيل. كانت الصلاة آخر شيءٍ يبقى حين يرحل كل شيء، خيطٌ رقيقٌ يصل بين إنسانٍ وحيدٍ في زمنٍ مجنون وشيءٍ أكبر من الزمن وأكبر من الجنون.', 'ذهب من ذهب وبقي من بقي. لكن البقاء نفسه صار يحتاج إلى شجاعة. أن تبقى في بلدك حين يُصبح البقاء خطراً هو نوعٌ من البطولة الصامتة. سنان أنطون يكتب هذه الرواية ليقول: لن ننسى. هؤلاء الناس عاشوا هنا وأحبّوا هذه الأرض ويستحقون أن تحمل ذاكرتها أسماءهم إلى الأبد.'], TRUE, 'رواية', 'واقعي / طائفي', 'سنان أنطون', 'دار الجمل', 2012, 192, 'العربية', '+16', '2026-06-19 21:06:16.269307+00'),
  ('771d34e9-3435-4492-a442-4f199319be41', 'رجال في الشمس', 'Men in the Sun', 'تحكي قصة ثلاثة فلسطينيين يحاولون التسلل إلى الكويت بحثاً عن حياة أفضل داخل صهريج مائي في الصحراء الحارقة. تُعدّ من أبرز روايات الأدب الفلسطيني في رصد معاناة اللاجئين والغربة والمأساة القومية.', 'The story of three Palestinians attempting to smuggle themselves to Kuwait in search of a better life inside a water tank in the scorching desert. It is considered one of the most prominent Palestinian literary works depicting refugee suffering and national tragedy.', 'https://www.neelwafurat.com/images/lb/abookstore/covers/normal/387/387068.jpg', ARRAY['الصحراء لم تكن تعرف الرحمة. كان الحر يقع على الأرض كحجرٍ ثقيل وكانت الشمس تلتهم كل شيءٍ في طريقها. جلس أبو قيس في ظل صخرةٍ صغيرة ومسح وجهه بكفّه ونظر إلى الطريق الممتد أمامه. كان الطريق يؤدي إلى الكويت حيث العمل والمال والحياة التي غاب عنها منذ فرّ من فلسطين وأرضه.', 'تذكّر أبو قيس ليلةً بعيدة حين كان نائماً في أرضه وكانت رائحة التراب المبلل بالمطر تملأ أنفه. كانت الزيتونات تهمس في الريح وكانت امرأته نائمةً بجانبه. فقدها وفقد الأرض في عامٍ واحد. كل ما يفعله الآن هو لأجل ما تبقّى: أبناؤه في المخيم الذين ينتظرون خبزاً وأملاً وأباً يعود.', 'أبو الخيزران كان يقود شاحنته كأنها مملكته الوحيدة. رجلٌ فقد شيئاً لا يُعوّض في حربٍ لا يريد أن يتذكرها. قال للرجال الثلاثة: سأنقلكم في الخزان الفارغ. وكانت الخطة بسيطةً كما يبدو الخطر دائماً قبل أن يتجلّى. مروان وأسعد وأبو قيس نظر كلٌّ منهم إلى الآخر وكانت في أعينهم إجابةٌ واحدة: لا خيار آخر.', 'دخل الرجال الخزان وأُغلق الباب عليهم. كانت الحرارة في الداخل لا تُطاق وكان الصمت مرعباً. كل واحدٍ منهم كان يفكر بشيءٍ مختلف: أبو قيس بأرضه ومروان بمستقبله وأسعد بحياةٍ لم تبدأ بعد. كانت الدقائق تمرّ كأنها ساعات والهواء يصبح أكثر ثقلاً مع كل نفَس.', 'توقفت الشاحنة طويلاً عند نقطة التفتيش وكان أبو الخيزران منشغلاً. حين فتح الخزان أخيراً كان الصمت من الداخل من نوعٍ آخر. دقّ على جدار الخزان مرةً ومرتين ثم نادى ولم يُجب أحد. الشمس أخذت الرجال الثلاثة في غفلةٍ من الزمن ومن العالم الذي لم يكترث لمصيرهم. غسان كنفاني يسألنا: لماذا لم يدقّوا على الجدران؟'], TRUE, 'رواية', 'سياسي / إنساني', 'غسان كنفاني', 'مؤسسة الأبحاث العربية', 1963, 108, 'العربية', 'مناسب للجميع', '2026-06-19 21:06:16.269307+00'),
  ('dfd28004-203d-4a99-a440-0bed44efe6fc', 'موسم الهجرة إلى الشمال', 'Season of Migration to the North', 'تحكي قصة مصطفى سعيد السوداني الذي درس في أوروبا وعاد إلى قريته محملاً بأسرار دفينة ومواجهات حضارية عميقة. تستكشف الرواية الصراع النفسي بين الشرق والغرب من خلال شخصيات مليئة بالتناقضات.', 'The story of Mustafa Saeed, a Sudanese man who studied in Europe and returned to his village carrying buried secrets. The novel explores the psychological conflict between East and West through complex, contradictory characters.', 'https://encrypted-tbn0.gstatic.com/images?q=tbn:ANd9GcRwu5E-uTj4zGkECycqbNrR0JmKNsSba-D2tebKSieqIg&s=10', ARRAY[]::TEXT[], FALSE, 'رواية', 'دراما نفسية', 'الطيب صالح', 'دار العودة', 1966, 168, 'العربية', '+18', '2026-06-19 21:06:16.269307+00'),
  ('48e8bf12-2d9a-44b3-9337-d9efbefb8269', 'مدن الملح', 'Cities of Salt', 'رواية ملحمية تحكي قصة تحول مجتمعات الخليج العربي من الحياة البدوية التقليدية إلى حقبة النفط والحداثة الصاخبة. تكشف عن التوترات الاجتماعية والسياسية الناجمة عن اكتشافات النفط وتغلغل الحضارة الغربية.', 'An epic novel about the transformation of Gulf societies from traditional Bedouin life to the tumultuous era of oil and modernity. It exposes the social and political tensions generated by oil discoveries and the penetration of Western civilization.', 'https://encrypted-tbn0.gstatic.com/images?q=tbn:ANd9GcR770jUM6Fl1hh9PY5aCgxoegVgJJUVmxkeeKIDGMwC6Q&s=10', ARRAY[]::TEXT[], FALSE, 'رواية', 'تاريخي / سياسي', 'عبد الرحمن منيف', 'المؤسسة العربية للدراسات والنشر', 1984, 404, 'العربية', 'مناسب للجميع', '2026-06-19 21:06:16.269307+00'),
  ('8ab552df-9cc2-4742-8816-2e73600a3c33', 'طوق الحمام', 'Tawq al-Hamama', 'رواية مكية سردية غنية تستكشف عالم مكة المكرمة وأزقتها القديمة من خلال حياة شخصيات متشابكة ومتداخلة. تمزج بين التراث الإسلامي والواقع المعاصر في سرد شعري فريد يأسر القارئ.', 'A richly narrative novel exploring the world of Mecca and its ancient alleyways through the lives of interwoven characters. It blends Islamic heritage and contemporary reality in a unique poetic narrative that captivates the reader.', 'https://encrypted-tbn0.gstatic.com/images?q=tbn:ANd9GcSnZmCUPfQ1UrCmHfUFOFCpaer1HA7_nys-d9-JYWR3yA&s=10', ARRAY[]::TEXT[], FALSE, 'رواية', 'شعري / مكاني', 'رجاء عالم', 'المركز الثقافي العربي', 2010, 520, 'العربية', '+16', '2026-06-19 21:06:16.269307+00'),
  ('5c17df26-fa46-4331-b9b2-eb51648a1d4b', 'عزازيل', 'Azazeel', 'رواية تاريخية تجري في القرن الخامس الميلادي تحكي قصة الراهب هيبا وصراعه الروحي الحاد بين الإيمان والشك. تستعرض حقبة الخلافات الدينية المسيحية الكبرى وصراع الهويات في الشرق القديم.', 'A historical novel set in the fifth century AD, recounting the story of monk Hypa and his intense spiritual struggle between faith and doubt. It explores the era of great Christian religious controversies and the clash of identities in the ancient East.', 'https://encrypted-tbn0.gstatic.com/images?q=tbn:ANd9GcSvULYk65kRozyK1046lIPXENLJ6g-YK3SOtc4A73O_jQ&s=10', ARRAY['أكتب هذه السطور على رقٍّ قديم في مكانٍ لا أُريد أن أُسمّيه. لا أستطيع أن أحمل هذا الثقل إلى قبري. اسمي هيبا وأنا راهبٌ مصري عشت في القرن الخامس الميلادي وشهدت ما شهدت. جئت إلى الإسكندرية شاباً باحثاً عن العلم وكانت المدينة مليئةً بالعلماء والفلاسفة والمتنازعين في شؤون الدين.', 'كنت أمشي بين الناس وأستمع إلى جدالاتهم وكان في قلبي سؤالٌ لم أجد له جواباً: إن كان الله رحيماً فلماذا يتقاتل عباده باسمه؟ رأيت أناساً يُؤذون بعضهم وهم يحسبون أنهم يتقرّبون إلى الله. وكان عزازيل الساكن في داخلي يُهمس: الإنسان لا يحتاج إلى عدوٍّ خارجيٍّ ما دام يحمل هذا العدو في نفسه.', 'قابلت مريم في الإسكندرية. كانت امرأةً لا تشبه ما عرفته من النساء. تتكلم الفلسفة وتُجادل العلماء بهدوءٍ يُربك المجادلين. أحببتها بطريقةٍ لم أفهمها وكان عزازيل يُهمس: هذا الحب سيدمّرك. لكنني لم أسمع لأن الإنسان حين يُحبّ يختار الصمم.', 'مات نيسطور في الجدل اللاهوتي الكبير وانقسمت الكنيسة. رحلت إلى شمال سوريا وبنيت لنفسي كوخاً بين الجبال وقضيت سنواتٍ في الصمت أُحاول أن أفهم. لكن الصمت لا يُجيب، والأسئلة الكبيرة لا تموت، تنام فقط وتعود بأصواتٍ أعلى مما كانت عليه.', 'هذه الأوراق هي شهادتي. لا أطلب المغفرة ولا الإدانة، أطلب أن يفهم من يقرأ أن الإنسان في صراعه مع نفسه ومع التاريخ يُبقي من نفسه ما يستحق الحفظ. يوسف زيدان كتب هذه الرواية ليُذكّرنا أن التاريخ لم يكن يوماً خطاً مستقيماً بل كان دائماً أرواحاً تتصارع وتُحاول أن تجد معنى.'], TRUE, 'رواية', 'تاريخي / ديني', 'يوسف زيدان', 'دار الشروق', 2008, 400, 'العربية', '+16', '2026-06-19 21:06:16.269307+00'),
  ('c208eb3f-450a-4e41-816e-b5670bf500ad', 'ساق البامبو', 'The Bamboo Stalk', 'تحكي قصة عيسى المولود من أب كويتي وأم فلبينية، يعيش بين عالمين متناقضين باحثاً عن انتمائه وهويته الضائعة. تتناول بعمق قضايا التعصب الطبقي والعنصرية والغربة في مجتمعات الخليج المعاصرة.', 'The story of Issa, born to a Kuwaiti father and a Filipino mother, living between two contradictory worlds in search of his lost identity. It deeply addresses class prejudice, racism, and alienation in contemporary Gulf societies.', 'https://encrypted-tbn0.gstatic.com/images?q=tbn:ANd9GcS99SXALUBXa6TlkzgbdX8McK703onmibjpQ5ztq4B8fw&s=10', ARRAY[]::TEXT[], FALSE, 'رواية', 'اجتماعي / إنساني', 'سعود السنعوسي', 'المؤسسة العربية للدراسات والنشر', 2012, 356, 'العربية', '+16', '2026-06-19 21:06:16.269307+00'),
  ('8f837078-f497-4a8f-9b86-b684707cc6b5', 'فرانكشتاين في بغداد', 'Frankenstein in Baghdad', 'في بغداد ما بعد الغزو، يجمع بائع الخردة هادي أجزاء جثث ضحايا الانفجارات ليخلق كياناً غريباً يطالب بالثأر. تعكس الرواية الفوضى والعنف والتفكك الاجتماعي في العراق خلال سنوات الحرب المظلمة.', 'In post-invasion Baghdad, junk dealer Hadi assembles body parts of explosion victims to create a strange entity demanding revenge. The novel reflects the chaos, violence, and social disintegration in Iraq during the dark years of war.', 'https://encrypted-tbn0.gstatic.com/images?q=tbn:ANd9GcRwhHJQYeYFCLN2A4ozO_N2E8lVSL92rqRC0ipLBj6_XQ&s=10', ARRAY[]::TEXT[], FALSE, 'رواية', 'رعب وتشويق', 'أحمد سعداوي', 'دار الجمل', 2013, 296, 'العربية', '+18', '2026-06-19 21:06:16.269307+00'),
  ('9d23655a-3cfd-4b49-9ae0-16d97a399830', 'ميرامار', 'Miramar', 'تجري أحداثها في بنسيون ميرامار بالإسكندرية حيث يلتقي شخصيات من مختلف الطبقات والأجيال في لحظة تحول مصيرية. يرصد محفوظ من خلالها التحولات الاجتماعية والسياسية في مصر خلال ستينيات القرن العشرين.', 'Set in the Miramar pension in Alexandria, where characters from different classes and generations meet at a pivotal moment. Mahfouz captures the social and political transformations of Egypt in the 1960s.', 'https://encrypted-tbn0.gstatic.com/images?q=tbn:ANd9GcTyXCkp1kl-WiDJsn0scxRONLq5-j0lp_qlhdULI9L0hA&s=10', ARRAY['في شقّةٍ قديمة بحي محطة الرمل بالإسكندرية تجمّع غرباء. كانت ماريانا صاحبة البنسيون تُديره بحبٍّ واهتمامٍ يشبه اهتمام الأم. جاء إليها عامر واصف شيخاً عجوزاً يريد أن يقضي ما بقي له من عمرٍ بعيداً عن ماضيه الحزين. الإسكندرية كانت تُناسبه: مدينةٌ تنسى وتتذكر في آنٍ واحد وترحب بكل من يريد أن يبدأ من جديد.', 'حوستو كان ضيفاً آخر في البنسيون. الشاب المتعلم الحائر بين طموحاته وواقعه. كان يجلس في الصالة ويُراقب الأيام تمرّ من نافذة الإسكندرية الكبيرة. الإسكندرية مدينةٌ لا تُخيّب الناظر: كل ساعةٍ فيها تحمل وجهاً مختلفاً، بحرٌ في الصباح وذاكرةٌ في المساء وأحلامٌ معلّقةٌ بين البيوت القديمة.', 'زهرة الفلاحة الصغيرة القادمة من الريف جاءت إلى المدينة بعيونٍ واسعة وحلمٍ يُقاوم كل شيء. لم تكن تعرف أن الجمال يُثير ما يُثير وأن المدينة الكبيرة تختلف كلياً عن القرية الصغيرة في طريقة تعاملها مع الأحلام والطموحات. لكنها كانت تحمل شيئاً أقوى من الخبرة: الإصرار.', 'هؤلاء البشر تحت سقفٍ واحد كانوا يُمثّلون مصر في مرحلةٍ مفصلية. الثورة وأحلامها وخيباتها والطموح والتخاذل والحب والمصلحة كلها تتقاطع في ميرامار. كان نجيب محفوظ يرى في البنسيون الصغير مرآةً للبلد الكبير: أشخاصٌ مختلفون يتلاقون تحت سقفٍ واحد ويتركون في بعضهم أثراً لا يُمحى.', 'في النهاية رحل كلٌّ في طريقه وبقيت الإسكندرية. المدينة التي شهدت حضاراتٍ كثيرة وما زالت تُشاهد وتُدوّن وتحتفظ في ذاكرتها بكل من مشى في شوارعها. نجيب محفوظ يقول: الأشخاص يمرّون والمدن تبقى، والبشر يُفيدون بعضهم حين يُصغي بعضهم لبعض ويتحمّل كلٌّ منهم مسؤوليةً في مسيرة الحياة المشتركة.'], TRUE, 'رواية', 'واقعي / اجتماعي', 'نجيب محفوظ', 'مكتبة مصر', 1967, 252, 'العربية', 'مناسب للجميع', '2026-06-19 21:06:16.269307+00'),
  ('7a1ec685-676a-42b8-8795-136fbd905c01', 'ذاكرة الجسد', 'Memory in the Flesh', 'رواية عاطفية وطنية جزائرية تحكي قصة حب استثنائي بين رسام فقد ذراعه في حرب التحرير الجزائرية وامرأة شابة. تمزج مستغانمي بين الذاكرة الجماعية والحنين والوطنية في أسلوب شعري فريد يترك أثراً عميقاً.', 'An Algerian emotional and national novel about an extraordinary love between a painter who lost his arm in the war of liberation and a young woman. Mستغانمي blends collective memory, nostalgia, and patriotism in a unique poetic style.', 'https://encrypted-tbn0.gstatic.com/images?q=tbn:ANd9GcSDE_LOeoqE-mERYivFGWDJeoEd8qlki8INTEkVNUZplA&s=10', ARRAY[]::TEXT[], FALSE, 'رواية', 'عاطفي / وطني', 'أحلام مستغانمي', 'دار الآداب', 1993, 432, 'العربية', '+18', '2026-06-19 21:06:16.269307+00'),
  ('c90e04bc-dde7-494e-a0ac-4ab25a34aca1', 'عمارة يعقوبيان', 'The Yacoubian Building', 'تستعرض حياة سكان عمارة يعقوبيان وسط القاهرة كنموذج للمجتمع المصري بكل تناقضاته وطبقاته الاجتماعية. يكشف الأسواني بجرأة عن الفساد السياسي والقمع الجنسي والتطرف الديني في مصر الحديثة.', 'A portrait of the residents of the Yacoubian Building in downtown Cairo as a microcosm of Egyptian society with all its contradictions. The Aswany boldly exposes political corruption, sexual repression, and religious extremism in modern Egypt.', 'https://encrypted-tbn0.gstatic.com/images?q=tbn:ANd9GcTljkQa5NvATvxoC-NQA9Hl0pbfrJaJR1LLQ8n9mnSwzQ&s=10', ARRAY[]::TEXT[], FALSE, 'رواية', 'واقعي / اجتماعي', 'علاء الأسواني', 'مكتبة مدبولي', 2002, 280, 'العربية', '+18', '2026-06-19 21:06:16.269307+00'),
  ('56e69878-ad19-434e-811e-4ce33363fbef', 'الفيل الأزرق', 'The Blue Elephant', 'رواية تشويق ورعب نفسي تحكي قصة الطبيب النفسي يحيى الذي يستقبل مريضاً قديماً يكشف له أسراراً مظلمة ومرعبة. تمزج بين الإثارة النفسية والعناصر الخارقة في عمل مشوق يأسر القارئ من أوله لآخره.', 'A psychological thriller and horror novel about psychiatrist Yahya who receives an old patient who reveals dark and terrifying secrets to him. It blends psychological suspense with supernatural elements in a gripping work that captivates the reader throughout.', 'https://m.media-amazon.com/images/S/compressed.photo.goodreads.com/books/1485105416i/16031620.jpg', ARRAY[]::TEXT[], FALSE, 'رواية', 'رعب وتشويق', 'أحمد مراد', 'الدار العربية للعلوم', 2012, 440, 'العربية', '+18', '2026-06-19 21:06:16.269307+00'),
  ('4260485b-5072-4b88-bda2-93b84b7c24ea', 'الخيميائي', 'The Alchemist', 'رواية فلسفية عالمية مترجمة للعربية تحكي رحلة الراعي سانتياغو عبر الصحراء بحثاً عن كنزه الخفي ومعنى حياته. تحمل رسائل عميقة عن اتباع الأحلام والاستماع لصوت القلب والبحث عن المعنى الحقيقي للوجود.', 'A globally acclaimed philosophical novel translated into Arabic, following the shepherd Santiago across the desert in search of his hidden treasure and the meaning of life. It carries profound messages about following dreams, listening to the heart, and seeking the true meaning of existence.', 'https://encrypted-tbn0.gstatic.com/images?q=tbn:ANd9GcSO6KKrIza-xv7M6CUCSxzBHbK2XzlPOJjxAzOkrLOLGg&s=10', ARRAY[]::TEXT[], FALSE, 'general', 'فلسفي / روحي', 'باولو كويلو', 'دار الفارابي', 1988, 188, 'العربية', 'مناسب للجميع', '2026-06-19 21:07:30.283711+00'),
  ('b3e77eb4-6a2b-49f5-8489-6f9bbf51cf3a', 'صيد الخاطر', 'Capturing the Thought', 'كتاب في التأملات الروحية والأخلاقية يجمع ابن الجوزي فيه خواطره وأفكاره العميقة في الحياة والدين والنفس البشرية. يُعدّ من كنوز التراث الإسلامي في التزكية الروحية والعلم النافع والحكمة البالغة.', 'A book of spiritual and ethical reflections in which Ibn al-Jawzi gathers his profound thoughts on life, religion, and the human soul. It is considered one of the treasures of Islamic heritage in spiritual purification, beneficial knowledge, and profound wisdom.', 'https://cdn.salla.sa/NygAa/TTDcWbMKk6NX8WHjjR3jZzr1qek8D4NyTxisRnZ3.jpg', ARRAY['قال الشيخ رحمه الله: اعلم أن العمر رأس المال وأن من أنفقه في غير ما يُقرّبه إلى ربه فقد خسر أعظم الخسارة. رأيت أقواماً أمضوا شبابهم في اللهو ففاجأهم الشيب وهم لا شيء. ورأيت أقواماً صغاراً استيقظوا مبكراً فكان لهم من العمر ما لم يكن لكثيرٍ من الشيوخ. الوقت كالسيف إن لم تقطعه قطعك.', 'تأمّلت في أحوال الناس فوجدت أن أكثرهم يبحث عن السعادة في الخارج وهي في الداخل. من ملك الدنيا كلها وقلبه خاوٍ فهو أفقر الناس. ومن لم يملك شيئاً ولكن في صدره سكينةٌ فهو أغنى الناس. لا يعرف قيمة الصحة إلا من فقدها ولا يعرف قيمة الوقت إلا من ضيّعه وعرف بعدها أنه لن يعود.', 'ومن صيد هذا الخاطر: لا تَعِد نفسك بغدٍ لا تعرف هل تبلغه. الإنسان الحكيم هو من يعمل اليوم ما يتمنى لو عمله أمس. وأشد الندامة ندامةٌ تأتيك حين لا ينفع الندم، حين يكون الوقت قد ولّى وكانت بيدك خيطٌ لو أمسكته لنجّاك. والحكيم لا يُفرّط في لحظةٍ يمكن أن تُصنع فيها خيراً.', 'في حق العلم يقول الشيخ: لا تحقر علماً صغيراً فمن الحبة تأتي الشجرة. رأيت طلاباً أعرضوا عن مسائل ظنّوها بسيطةً فعجزوا عن الكبار. ورأيت طالباً آخر كان يُجيد الصغير فوصل إلى ما لم يصله كثيرون. العلم بنيانٌ لا تُبنى طوابقه إلا على أساسٍ متين وكل طابقٍ يحتاج إلى ما قبله.', 'آخر ما أودّ قوله: كن صادقاً مع نفسك قبل أن تكون صادقاً مع غيرك. الإنسان الذي يكذب على نفسه لا يمكن أن يصل إلى شيءٍ حقيقي. وإن وجدت في نفسك عيباً فلا تُكثر من الاعتذار بل من الإصلاح. لكلٍّ منا خاطرٌ صيد فاصطد خاطرك قبل أن تمرّ به اللحظة ولا تعود.'], TRUE, 'general', 'روحي / تأملي', 'ابن الجوزي', 'دار ابن الجوزي', 1165, 350, 'العربية', 'مناسب للجميع', '2026-06-19 21:07:30.283711+00'),
  ('e7637529-1229-4aaa-a7d0-bf1cd234b671', 'لسان العرب', 'Lisan al-Arab', 'أكبر المعاجم العربية وأشملها، موسوعة لغوية جامعة تضم مئات الآلاف من الكلمات وشواهدها الشعرية والنثرية. أمضى ابن منظور عمره في تأليفه ليصبح المرجع الأول الذي لا غنى عنه لكل مشتغل باللغة العربية.', 'The largest and most comprehensive Arabic dictionary, a linguistic encyclopedia containing hundreds of thousands of words with their poetic and prose examples. Ibn Manzur dedicated his life to composing it, making it the indispensable primary reference for every Arabic language scholar.', 'https://m.media-amazon.com/images/S/compressed.photo.goodreads.com/books/1380360973i/18591387.jpg', ARRAY['يقول ابن منظور: هذا كتابٌ جمعت فيه من لغة العرب ما يُحتاج إليه. واللغة العربية أشرف اللغات وأوسعها وأدقّها في التعبير عن مكنونات النفس ودقائق المعاني. وقد صرفت في جمعه الأعمار وبذلت فيه المجهود رجاء أن يكون ذخيرةً تُغني الباحث وزاداً يُعين الكاتب على أداء حقّ الكلمة.', 'ألّف الله تعالى هذه اللغة تأليفاً عجيباً: كل كلمةٍ فيها أصلٌ وكل أصلٍ له عائلة. فمن الجذر كتب تخرج الكتابة والكتاب والكاتب والمكتبة والمكتوب. هذه البنية الجذرية تجعل العربية لغةً تُولد من بعضها كالشجرة المتناسلة. ومن يعرف الجذور يعرف اللغة كلها.', 'ومن غرائب هذه اللغة أن فيها للسيف نحو خمسمئة اسم وللأسد أسماءٌ لا تُحصى وللبحر وصفاتٌ تملأ صفحات. لم يكن ذلك ترفاً بل كان انعكاساً لحضارةٍ عاشت مع البيئة واستوعبتها استيعاباً كاملاً. كل اسمٍ كان يحمل معلومةً دقيقة عن طبيعة الشيء وحاله وصفاته.', 'ومن أسرار اللغة العربية المضاد: تجد الكلمة وضدّها من نفس الجذر أحياناً كالجون الذي يعني الأبيض والأسود معاً. وهذا يُوحي بأن العقل العربي كان يُدرك أن الأشياء لا تُعرف حقيقتها إلا بضدّها. الليل يُعرف بالنهار والصمت يُعرف بالصوت والحزن يُعرف بالفرح.', 'ختاماً: من أراد أن يُتقن العربية فليُكثر من التأمّل في كلام الله وكلام فصحاء العرب الأوائل. ليس اللسان العربي مجرد وسيلةٍ للتواصل بل هو جسرٌ إلى حضارةٍ كاملة. من ملك هذه اللغة فتحت له أبوابٌ من المعرفة والجمال والحكمة لا يعرف كيف تُغلق.'], TRUE, 'general', 'لغة ومعجم', 'ابن منظور', 'دار صادر', 1290, 7200, 'العربية', 'مناسب للجميع', '2026-06-19 21:07:30.283711+00'),
  ('d0c7a19d-190f-4ce0-bc8a-03a18faf625b', 'وحي القلم', 'Inspiration of the Pen', 'مجموعة مقالات أدبية وفلسفية تجمع بين البلاغة العربية الأصيلة والتأمل العميق في الحياة والكون والإنسان. يعكس الرافعي في هذا الكتاب قمة عطائه الأدبي وأسلوبه الفريد في النثر العربي الجميل المتدفق.', 'A collection of literary and philosophical essays combining authentic Arabic rhetoric with deep contemplation of life, the universe, and humanity. Al-Rafi reflects in this book the pinnacle of his literary genius and his unique style in flowing, beautiful Arabic prose.', 'https://encrypted-tbn0.gstatic.com/images?q=tbn:ANd9GcTecoI_qoxt4rZZ5CDzk2t2HjzAw5DBYyFtuttcvHjqaw&s=10', ARRAY['الكلمة أمانةٌ في عنق من يكتبها. هذا ما يؤمن به مصطفى صادق الرافعي ويُجسّده في كل سطرٍ كتبه. ليست الكتابة عنده مجرد حرفةٍ أو موهبةً بل هي مسؤوليةٌ تجاه اللغة وتجاه من يقرأ وتجاه الحق الذي يجب أن يُقال. ومن لا يحمل هذا الإحساس فهو حارفٌ للكلمات لا كاتبٌ حقيقي.', 'العربية في قلب الرافعي شمسٌ لا تغيب. كان يُدافع عنها بقلمٍ أحدّ من السيف. حين قال بعضهم إن عصر الأساليب الرفيعة قد مضى قال الرافعي: بل عصره يبدأ دائماً من جديد مع كل من يجلس إلى الورقة البيضاء بقلبٍ نقيٍّ وعزمٍ صادق. الجمال لا يموت إنما ينتقل من جيلٍ إلى جيل.', 'من وحي القلم في الطبيعة: الشجرة في الخريف حين تُلقي ورقها ليست تموت بل تستعدّ لربيعٍ جديد. وكذلك الكاتب الحق حين يُمزّق ما كتب ليس يُتلف عمله بل يُقرّب نفسه من الكمال الذي يرنو إليه. الكتابة رحلةٌ لا تنتهي والوصول فيها حلمٌ جميلٌ لا يمنعك من مواصلة السير.', 'يتأمّل الرافعي في الجمال: الجمال الحقيقي ليس في الزخرف والتزويق بل في الصدق والوضوح. الجملة الجميلة كالشعر تقول المعنى وتُضيف إليه بُعداً لم يتوقعه القارئ. ولهذا تبقى جملٌ قُرئت منذ مئة عام حيّةً كأنها كُتبت اليوم لأن الصدق لا يتقادم ولا تأكله السنون.', 'وهذا هو وحي القلم: ليس وحياً من السماء بل وحيٌ يأتي من عمقٍ في الإنسان حين يُصفّي نفسه ويُهيئها للتلقّي. الكاتب الحق يُصغي لهذا الصوت الخافت ويُترجمه إلى كلمات. وحين يتوافق الصوت الداخلي مع الكلمة المكتوبة يُولد النص الذي يصل إلى القارئ مباشرةً كسهمٍ إلى الهدف لا يتوقف في الطريق.'], TRUE, 'general', 'أدب وبلاغة', 'مصطفى صادق الرافعي', 'دار الكتاب العربي', 1934, 400, 'العربية', 'مناسب للجميع', '2026-06-19 21:07:30.283711+00'),
  ('e620d8e4-82b4-4ace-bb40-580bad7a7df3', 'مقدمة ابن خلدون', 'The Muqaddimah', 'موسوعة فكرية تُعدّ من أعظم الأعمال في التاريخ الإنساني، تتناول فلسفة التاريخ وعلم الاجتماع والسياسة والاقتصاد. وضع فيها ابن خلدون نظرية العصبية وقوانين قيام الدول وانهيارها بمنهجية علمية سبقت عصرها بقرون.', 'An intellectual encyclopedia considered one of the greatest works in human history, addressing philosophy of history, sociology, politics, and economics. Ibn Khaldun laid out his theory of social cohesion and the laws of the rise and fall of civilizations centuries ahead of his time.', 'https://encrypted-tbn0.gstatic.com/images?q=tbn:ANd9GcR2CYtl9CfnNMoFkilu9FEm0BVvpRYMkrw7rThJ6MA8IA&s=10', ARRAY['إن التاريخ في ظاهره لا يزيد على الإخبار عن الأيام والدول. أما في باطنه فهو نظرٌ وتحقيقٌ وتعليلٌ للكائنات ومبادئها دقيق. والمؤرّخ الحق ليس من يجمع الأخبار بل من يُميّز صحيحها من سقيمها ويفهم ما وراءها من أسباب وعلل. وهذا ما يجعل علم التاريخ أكثر من مجرد سردٍ للوقائع.', 'العمران البشري له طبيعةٌ وقوانين. الجماعات الإنسانية تبدأ بدويةً تجمعها العصبية ثم تنتقل إلى الحضارة والملك. وفي الحضارة تنعّم الناس وكثر الترف وفي الترف ابتدأت نواة الضعف. وهكذا تدور الدول في دورةٍ تُشبه تعاقب الفصول. لا شيء يبقى على حاله إلى الأبد.', 'العصبية هي الرابط الذي يجعل الجماعة قادرةً على البناء والدفاع. حين تضعف العصبية يُصبح المجتمع هشاً. وليست العصبية قبليةً فحسب بل هي كل رابطٍ يجمع الناس: دينٌ أو وطنٌ أو فكرة. من جمعتهم فكرةٌ عظيمة كانوا أشدّ قوةً ممن جمعهم الخوف أو المصلحة الضيّقة.', 'رأى ابن خلدون قبل الاقتصاديين الغربيين بقرون أن الأسعار ترتفع وتنخفض تبعاً للعرض والطلب وأن الضرائب الباهظة تُضعف الإنتاج. والرخاء يُولّد الطلب على الكماليات وهذا يُشجّع الحرف والصناعات وهذا بدوره يدعم العمران. الاقتصاد والسياسة والاجتماع عنده ثلاثةٌ لا تنفصل.', 'يختم ابن خلدون بالتواضع: ما كتبته ليس آخر القول بل أوّله. والتاريخ البشري أكبر من أن يستوعبه عقلٌ واحد. لكنني أرجو أن أكون وضعت أساساً يبني عليه من يأتي بعدي. فالعلوم تُبنى بالتراكم والتراكم يبدأ بأول حجر. وربما كانت هذه المقدمة ذلك الحجر الأول.'], TRUE, 'general', 'فلسفة وفكر', 'ابن خلدون', 'دار الكتب العلمية', 1377, 900, 'العربية', 'مناسب للجميع', '2026-06-19 21:07:30.283711+00'),
  ('9f6a4150-d64c-4cb2-bfdb-d6a37e870746', 'طوق الحمامة', 'The Ring of the Dove', 'رسالة أدبية رفيعة في علم الحب والعاطفة كتبها ابن حزم في الأندلس تجمع بين الفلسفة والشعر والتأمل الإنساني العميق. يستعرض فيها طبائع المحبين وأحوال العشق بأسلوب أنيق يعكس ثقافة الحضارة الأندلسية في أزهى عصورها.', 'A refined literary treatise on the nature of love and emotion written by Ibn Hazm in Andalusia, combining philosophy, poetry, and deep human reflection. He explores the nature of lovers and the states of passion in an elegant style that reflects Andalusian civilization at its peak.', 'https://encrypted-tbn0.gstatic.com/images?q=tbn:ANd9GcQ0qydztZRegk_sSU8ZQvsI2dMzG_3ZMKgITt1DUk2joQ&s=10', ARRAY['يقول ابن حزم: الحب بدايته هزلٌ وآخره جدّ. دقّت معانيه جداً حتى تعذّر على واصفيه وصفه وعسر على المدّعين إدراك حقيقته. لا يُعرف إلا بآثاره. أما ما يقوله الناس عن أسبابه فأكثره ظنٌّ لا يقين إذ لو كانت له أسبابٌ معروفة لسهل علاجه وما بقي طوّافاً بين القلوب كالروح في الجسد.', 'علاماتُ الحب كثيرة وأولها إدامة النظر. فعيون المحبّ لا تعرف الراحة حين يكون محبوبه بحضرتها وهي تتبعه حيث تحرّك وتُلازم مكان جلوسه حين يغيب. وعلامةٌ ثانية الإنصات الشديد لكلامه والاستبشار بذكر اسمه. وعلامةٌ ثالثة أن تجد نفسك تتحدث عنه في كل حديثٍ من غير قصد.', 'من أعجب ما يصنعه الحب أنه يُساوي بين الناس. الحب لا يُفرّق بين ذي مالٍ ومعدم ولا بين كبيرٍ وصغير. رأيت رجلاً من كبار الأندلس يبكي بكاء المرأة لهجرٍ أصابه ورأيت فقيراً لا يملك شيئاً غير أن قلبه مرتاحٌ وفيه من الحب ما يكفي العالمين.', 'في باب العلاج يقول ابن حزم: لا شفاء من الحب إلا بمقابله أو بالإياس التام منه. فأما التشاغل والنسيان فتخفيفٌ لا علاج حقيقي. رأيت من أيقنوا أنهم نسوا ثم مرّ بهم صوتٌ أو رائحةٌ أو ذكرى فعاد ما كانوا يظنونه مات. الحب كالجمرة تحت الرماد، تبدو منطفئةً وتظل حيّة.', 'وهذا كتاب طوق الحمامة كتبته من تجربتي وما شاهدته في بلاد الأندلس المباركة. ليس فيه إلا صدقٌ رأيته وحقٌّ لمسته. لا أُحلل الحب لأكشف عيبه بل لأفهم هذا الجانب من الطبيعة البشرية الذي يجعل الإنسان إنساناً في أكمل صورته حين يُحبّ ويُحبّ ويمنح قلبه دون خوف.'], TRUE, 'general', 'أدب / عاطفيات', 'ابن حزم الأندلسي', 'دار المعارف', 1022, 200, 'العربية', '+16', '2026-06-19 21:07:30.283711+00'),
  ('f288903e-27c3-4894-a8a1-90f1ac8b26ac', 'حديث الأربعاء', 'Wednesday Talk', 'مجموعة من المحاضرات الأدبية النقدية التي ألقاها طه حسين في جامعة القاهرة حول الأدب العربي القديم والحديث. يقدم عميد الأدب العربي رؤيته الثاقبة في النقد الأدبي مع تحليل عميق للشعر والنثر العربيين عبر العصور.', 'A collection of literary and critical lectures delivered by Taha Hussein at Cairo University on classical and modern Arabic literature. The dean of Arabic literature presents his incisive vision of literary criticism with deep analysis of Arabic poetry and prose across the ages.', 'https://www.neelwafurat.com/images/lb/abookstore/covers/normal/408/408337.jpg', ARRAY[]::TEXT[], FALSE, 'general', 'نقد أدبي', 'طه حسين', 'دار الكتب المصرية', 1925, 300, 'العربية', 'مناسب للجميع', '2026-06-19 21:07:30.283711+00'),
  ('1b76f053-7e58-4256-872b-b65f9af90df3', 'عبقرية محمد', 'The Genius of Muhammad', 'دراسة أدبية وفكرية معمقة تتناول شخصية النبي محمد صلى الله عليه وسلم وعبقريته القيادية والروحية والحضارية. يحلل العقاد جوانب شخصيته الإنسانية بأسلوب موضوعي متميز يمزج بين النقد الأدبي والرؤية التاريخية الثاقبة.', 'An in-depth literary and intellectual study of the Prophet Muhammad, examining his leadership genius and spiritual and civilizational dimensions. Al-Aqqad analyzes the human aspects of his character with a distinctive objective style blending literary criticism and sharp historical insight.', 'https://encrypted-tbn0.gstatic.com/images?q=tbn:ANd9GcQkw0Ly4udYCfhb4u1qa83v8UOmo1ZqrHDGB5AleeA1dw&s=10', ARRAY['ما الذي يجعل إنساناً يُغيّر مجرى التاريخ؟ هذا السؤال هو الذي قادنا إلى دراسة شخصية النبي محمد صلى الله عليه وسلم. ليس الهدف مجرد الإطراء بل محاولة الفهم: ما طبيعة العقل الذي خرج من بيئةٍ واحدة ليُخاطب الإنسانية كلها ويُقدّم لها منظوماً أخلاقياً لا تزال الحضارة تعيش بظلاله بعد أكثر من أربعة عشر قرناً.', 'كان النبي صادقاً قبل أن يكون نبياً. وهذه شهادةٌ لم يُتنازع فيها حتى أعداؤه. الصادق الأمين لقبٌ أطلقه عليه قومه قبل البعثة، وهذا يدلّ على أن الشخصية القوية لا تبدأ بالمعجزات بل تبدأ بالصدق في التفاصيل الصغيرة اليومية التي لا يُلاحظها إلا من يُعايش الإنسان.', 'في مواجهة التحديات كان لا يتزعزع. حين قالوا له إن قريشاً تُريد أن تمنعه قال: والله لو وضعوا الشمس في يميني والقمر في يساري على أن أترك هذا الأمر ما تركته. هذه كلمات رجلٍ يحمل يقيناً لا يُقايض به شيئاً في الدنيا. والإنسان المؤمن بقضيته يُشعّ من حوله ما لا تستطيع الجيوش أن تُشعّه.', 'رأفته لم تكن ضعفاً. حين فتح مكة قال للذين آذوه: اذهبوا فأنتم الطلقاء. هذا العفو الكبير لم يكن تهاوناً بل كان مُراداً به بناء مجتمعٍ جديد لا الانتقام من مجتمعٍ قديم. ومن يتأمّل تاريخه يجد أن أعظم انتصاراته لم تكن في المعارك بل في قلوب الناس.', 'عبقرية محمد لم تكن في موهبةٍ فردية بل في القدرة على إيصال الحق إلى قلوب الناس بلا حواجز. كل إنسانٍ يقرأ سيرته يجد فيها ما يُخاطبه شخصياً سواء كان فقيراً أو غنياً ضعيفاً أو قوياً. هذه الشمولية هي علامة العبقرية الحقيقية كما يقول العقاد.'], TRUE, 'general', 'سيرة وتاريخ', 'عباس محمود العقاد', 'دار الكتاب العربي', 1942, 350, 'العربية', 'مناسب للجميع', '2026-06-19 21:07:30.283711+00'),
  ('ff45592e-8656-45dd-93dd-23ca0072f353', 'حياة في الإدارة', 'A Life in Administration', 'سيرة إدارية وفكرية يحكي فيها غازي القصيبي تجربته الطويلة في العمل الحكومي والسياسي في المملكة العربية السعودية. يمزج القصيبي بين الحكمة الإدارية والأسلوب الأدبي اللافت في كتاب نادر يجمع الخبرة والطرافة والعمق.', 'An administrative and intellectual memoir in which Ghazi al-Gosaibi recounts his long experience in government and political work in Saudi Arabia. Al-Gosaibi blends administrative wisdom with a striking literary style in a rare book that combines experience, wit, and depth.', 'https://encrypted-tbn0.gstatic.com/images?q=tbn:ANd9GcQ1sJHCHsfaxfUtoc9BEsJCXfTU7dbMlbRT-DrwiWWang&s=10', ARRAY[]::TEXT[], FALSE, 'general', 'إدارة وقيادة', 'غازي القصيبي', 'المؤسسة العربية للدراسات والنشر', 1999, 310, 'العربية', 'مناسب للجميع', '2026-06-19 21:07:30.283711+00'),
  ('b0bc95b8-f3d9-4050-ab46-26bd32a9254a', 'مهزلة العقل البشري', 'The Farce of Human Reason', 'دراسة اجتماعية نقدية تحليلية تتناول التناقضات والمفارقات في سلوك الإنسان العربي وتفكيره بأسلوب جريء ونافذ. يكشف الوردي بأسلوب ساخر ومنهجي عن أسباب التخلف الاجتماعي والفكري في المجتمعات العربية.', 'An analytical social critique addressing the contradictions and paradoxes in Arab human behavior and thought in a bold, penetrating style. Al-Wardi reveals with satirical and methodical precision the causes of social and intellectual stagnation in Arab societies.', 'https://encrypted-tbn0.gstatic.com/images?q=tbn:ANd9GcT6OYSvGy_41__86wtF0_X1WRDSwlElnbKHD06FzCIGGg&s=10', ARRAY[]::TEXT[], FALSE, 'general', 'اجتماع وفكر', 'علي الوردي', 'مطبعة العاني', 1955, 256, 'العربية', 'مناسب للجميع', '2026-06-19 21:07:30.283711+00'),
  ('a28b7a07-94bd-41c6-b8c7-52d89c0a08f6', 'هكذا خلقت', 'Thus Was I Created', 'عمل أدبي فلسفي يتناول رحلة الإنسان الداخلية في البحث عن المعنى والحقيقة وسط تحولات الحياة الكبرى. يجمع هيكل بين التأمل الفلسفي العميق والأسلوب الأدبي الراقي في دراسة طبيعة الإنسان وغاية وجوده.', 'A literary and philosophical work addressing the inner journey of the human being in search of meaning and truth amid the great transformations of life. Heikal combines deep philosophical contemplation with an elevated literary style in studying human nature and the purpose of existence.', 'https://encrypted-tbn0.gstatic.com/images?q=tbn:ANd9GcRUIhoe16dRxb8teKWJSbf9hLKS5QmPKscvIyAAKbBf0Q&s=10', ARRAY[]::TEXT[], FALSE, 'general', 'فلسفة وفكر', 'محمد حسين هيكل', 'دار المعارف', 1955, 280, 'العربية', 'مناسب للجميع', '2026-06-19 21:07:30.283711+00'),
  ('25b62db3-cf7d-4ce5-9bea-637914385f84', 'تجديد الفكر العربي', 'Renewal of Arab Thought', 'كتاب فلسفي تنويري يدعو إلى مصالحة العقل العربي مع الحداثة العلمية دون التخلي عن الجذور الحضارية الأصيلة. يقدم زكي نجيب محمود رؤية جديدة تجمع بين الوضعية المنطقية والتراث الفكري العربي الإسلامي.', 'An enlightenment philosophical book calling for reconciling the Arab mind with scientific modernity without abandoning authentic civilizational roots. Zaki Naguib Mahmoud presents a new vision combining logical positivism with the Arab-Islamic intellectual heritage.', 'https://encrypted-tbn0.gstatic.com/images?q=tbn:ANd9GcR0TbLtvcK5hCemTClBrWvrYmsZrF4jdiWr-bZwa_HQVw&s=10', ARRAY[]::TEXT[], FALSE, 'general', 'فلسفة وتنوير', 'زكي نجيب محمود', 'دار الشروق', 1971, 320, 'العربية', 'مناسب للجميع', '2026-06-19 21:07:30.283711+00'),
  ('a11aba4f-5eb1-43eb-b551-edfdbb538c37', 'طبائع الاستبداد ومصارع الاستعباد', 'The Nature of Despotism', 'كتاب سياسي فكري جريء يحلل آليات الاستبداد السياسي وأثره المدمر على المجتمعات الإسلامية والعربية بعمق نادر. كتبه الكواكبي في نهاية القرن التاسع عشر وما زال من أبرز المراجع في الفكر السياسي العربي التحرري.', 'A bold political and intellectual book analyzing the mechanisms of political despotism and its devastating impact on Islamic and Arab societies with rare depth. Written by al-Kawakibi in the late nineteenth century, it remains one of the most prominent references in Arab liberal political thought.', 'https://encrypted-tbn0.gstatic.com/images?q=tbn:ANd9GcS1iHU5P8AIXSrA9LJvZuLHWI4uLsExSW1Fy-usPCcskw&s=10', ARRAY['الاستبداد آفةٌ عرفتها البشرية منذ فجر تاريخها. هو ليس مجرد ظلمٍ سياسي بل هو داءٌ يصيب العقول قبل أن يصيب الأجساد. حين يتعوّد الناس على الذل يُصبح الذل طبيعةً وحين تُعدم فيهم الإرادة لا تُعيدها إليهم سلاحٌ أو ثورة بل يعيدها التعليم والوعي والحرية البطيئة المتراكمة عبر الأجيال.', 'المستبد يحتاج إلى معاونين، وهم لا يُعانونه من خوفٍ فحسب بل كثيراً ما يُعانونه طمعاً. الطمع أخطر من الخوف لأن الخائف يتحرك حين يجد الأمان أما الطامع فلا يتحرك إلا حين يفقد مصلحته. لهذا يحرص المستبد دائماً على أن يكون بيده مفاتيح المصالح ويُفرّق ليسود.', 'لا تزدهر الأمة تحت الاستبداد. الأمم كالنباتات تحتاج إلى ضوء الحرية كي تنمو. من يرى أن الاستقرار يتحقق بالقوة مخطئ لأن الاستقرار القائم على الخوف بنيانٌ واهٍ ينهار بأول موجة. الاستقرار الحقيقي يأتي من شعبٍ يؤمن بوطنه ويختار أن يُدافع عنه لا شعبٍ مقهورٍ يُطيع خشيةً.', 'يقول الكواكبي: دواء الاستبداد الانتشار والنجدة. الانتشار أن يُدرك كل فردٍ في الأمة حقيقة ما يعيشه وأن يُسمّيه باسمه. والنجدة أن يلتفّ الناس على بعضهم ويشعروا أنهم أمةٌ واحدة لا أفراداً مبعثرين. المستبد يخاف شيئاً واحداً: الشعب الذي يعرف نفسه ويعرف حقوقه.', 'تاريخ البشرية مليءٌ بأممٍ ظنّت أنها لن تُشفى فعادت إلى الحياة. الحرية بذرةٌ عجيبة تعيش في أقسى الأتربة وتبقى حيّةً إلى أن يأتي الموسم المناسب. الكواكبي كتب هذا الكتاب في زمنٍ كان الكلام فيه خطراً والصمت أسهل. اختار الكلام لأنه كان يعرف أن الكلمة الصادقة لا تموت.'], TRUE, 'general', 'سياسة وفكر', 'عبد الرحمن الكواكبي', 'مطبعة المقتبس', 1900, 150, 'العربية', 'مناسب للجميع', '2026-06-19 21:07:30.283711+00'),
  ('25140f83-6a6b-4241-b868-1bb4627bd6f0', 'كليلة ودمنة', 'Kalila and Dimna', 'كتاب فلسفي أخلاقي من أروع ما أُلّف في الأدب العربي، يقدم الحكمة والموعظة على ألسنة الحيوانات في أسلوب بديع. ترجمه ابن المقفع وأضاف إليه من بلاغته ما جعله تحفة أدبية خالدة عبر الأجيال.', 'A philosophical and ethical masterpiece of Arabic literature presenting wisdom and moral lessons through the voices of animals in a magnificent style. Translated and enriched by Ibn al-Muqaffa, whose eloquence transformed it into an immortal literary treasure across generations.', 'https://encrypted-tbn0.gstatic.com/images?q=tbn:ANd9GcSqiBH768yjrFeIt6gYVxC6FdKJ3qsn-y9ztSQkzzBvsw&s=10', ARRAY['قال دبشليم الملك للفيلسوف بيدبا: أريد أن أعرف مثل رجلٍ يملك صديقاً صادقاً ثم يُسيء الظنّ به بسبب كلام واشٍ. فقال بيدبا: مثله يا ملك الزمان مثل الأسد الذي ملك الغابة وأسكن في كنفه الثور شنزبة فأُولع به وأكرمه ثم جاءه دمنة بالأكاذيب الملوّنة فقتله وندم بعد فوات الأوان.', 'كان الأسد ملكاً عادلاً تهابه الغابة وتحبّه. سمع يوماً صوتاً عالياً لم يسمع مثله فارتاع. فقال دمنة: أنا أعرف أصل هذا الصوت وأنا أجلبه لك. وكان دمنة يُريد بهذا أن يكسب مكانةً عند الملك على حساب غيره. وهكذا يبدأ الفساد دائماً: برجلٍ يُريد أن يرقى على أكتاف الآخرين.', 'حين تعارف الأسد والثور وصارا صديقين حسد دمنة ما وصل إليه الثور من المنزلة. بدأ يدور بالكلام بين الاثنين يُوهم كلاً منهما أن الآخر يُضمر له الشر. والكلمة المدسوسة كالسم في الماء: لا لونٌ لها ولا طعم لكن عملها يظهر متأخراً حين يصعب العلاج.', 'من حكمة هذا الباب: إيّاك أن تُصغي لمن يأتيك بحكاياتٍ يُدنّس فيها أصحابك. فإن الواشي لا يأتيك بكلامٍ فارغٍ بل يُعطيك نصف الحقيقة وهو الأخطر. الصديق الحقيقي كالذهب لا يتغيّر بالنار، فمن أراد أن يختبر صداقةً فليراها في لحظات الشدة لا في أوقات الرخاء.', 'في باب الحمامة الطوقاء: حين وقع الصيّاد على الحمامات بشبكته طارت فالتفّت وحملت الشبكة بأجنحتها معاً ونجت. ثم ذهبت إلى الفأر فقطع حبال الشبكة وأطلقها. من هنا يُدرك العاقل أن لا نجاح في الانفراد وأن قوة الإنسان في أخيه الإنسان. كليلة ودمنة حكمةٌ تُلبس ثوب الحيوان لتصل إلى قلب الإنسان.'], TRUE, 'general', 'حكم وأمثال', 'ابن المقفع', 'دار صادر', 750, 280, 'العربية', 'مناسب للجميع', '2026-06-19 21:07:30.283711+00'),
  ('83ba805d-8d3e-4f22-bbb9-b9f4921d7503', 'الأيام', 'The Days', 'سيرة ذاتية أدبية خالدة تحكي حياة طه حسين في طفولته وصباه في الريف المصري بعد أن فقد بصره في سن مبكرة. تُعدّ من أجمل ما أنتجه الأدب العربي الحديث في التعبير عن تجربة الإعاقة والعلم والإرادة الصلبة.', 'An immortal literary autobiography recounting the childhood and youth of Taha Hussein in the Egyptian countryside after he lost his sight at an early age. It is considered one of the most beautiful works of modern Arabic literature in expressing the experience of disability, knowledge, and iron will.', 'https://www.neelwafurat.com/images/lb/abookstore/covers/normal/327/327297.jpg', ARRAY['كان الطفل الصغير يجلس في ركن الحجرة ويسمع أصوات البيت من حوله. لم يكن يرى وجوه إخوته لكنه كان يعرف خطواتهم وأنفاسهم وطريقة كل واحدٍ منهم في الضحك. العالم لديه كان أصواتاً كثيرةً تتشابك وكان يُفرزها بدقةٍ مذهلة. لم يكن يشعر بالغبن دائماً لكن كانت لحظاتٌ تأتيه فيها موجةٌ من الحزن لا يعرف لها سبباً تجعله يمدّ يده في الهواء كأنه يبحث عن شيءٍ ضائع.', 'في الكتّاب تعلّم الطفل أن الحروف لها أسرار. كان الشيخ يلفظ الكلمات بصوتٍ عميق وكان الطفل يردد خلفه بإتقانٍ يدهش الجميع. حفظ القرآن الكريم بسرعةٍ لم يتوقعها أحد وكان الشيخ يتساءل في سره: هل العمى هبةٌ تجعل الإنسان يسمع ما لا يسمعه الآخرون؟ كانت الكلمة في فمه تأخذ شكلاً مختلفاً عن الكلمة في أفواه أقرانه، أكثر عمقاً وأطول عمراً.', 'رحلة القاهرة كانت أول تحدٍّ حقيقي. المدينة الكبيرة صخبٌ دائم: أصواتٌ فوق أصوات، أقدامٌ على رصيف، باعةٌ يصيحون وعرباتٌ تمر. كان الطفل يمشي بيده ممسكةً بذراع أخيه لكن قلبه كان يريد أن يمشي وحده. تعلّم الأزقة بقدميه وتعلّم الناس بكلامهم. في القاهرة كان غريباً بين غرباء لكن الغرابة علّمته الاستقلالية وأن يثق بسمعه وحكمته.', 'في الأزهر الشريف جلس بين علماءٍ وطلاب. استمع إلى التفسير والنحو والأدب والفقه وكان يأخذ بيده كل علمٍ ويضمه إلى ما يحمله من قبل. وتدريجياً تحوّل الطالب الخائف إلى باحثٍ يسأل ويجادل. رأى في نفسه أن الكتب كانت نوره في ظلامه وأن العقل يرى حين تغمض العيون. كانت كل مسألةٍ علمية يفهمها تُضيء جزءاً من ذلك الداخل المعتم.', 'في باريس رأى طه حسين ما لم يتخيّله، بعيونٍ لا تُبصر ولكن بعقلٍ مفتوح كالسماء. تعلّم الفلسفة الغربية والتاريخ والنقد الأدبي وعاد إلى مصر مختلفاً. كتب كتابه الأيام ليقول للعالم: إن أصعب العمى ليس عمى البصر بل عمى القلب. من يُريد أن يرى فلن يمنعه من ذلك شيء، لأن الرؤية الحقيقية تسكن في الإرادة لا في العيون.'], TRUE, 'general', 'سيرة ذاتية', 'طه حسين', 'دار المعارف', 1929, 330, 'العربية', 'مناسب للجميع', '2026-06-19 21:07:30.283711+00');
